import{c as t,Q as s,j as a,m as i}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Claude Code 新工具與 Slash Commands（2026）","description":"","frontmatter":{},"headers":[],"relativePath":"research/best-practices/30-new-tools-commands.md","filePath":"research/best-practices/30-new-tools-commands.md","lastUpdated":1779935873000}'),d={name:"research/best-practices/30-new-tools-commands.md"};function r(n,e,o,p,l,h){return s(),a("div",null,[...e[0]||(e[0]=[i(`<h1 id="claude-code-新工具與-slash-commands-2026" tabindex="-1">Claude Code 新工具與 Slash Commands（2026） <a class="header-anchor" href="#claude-code-新工具與-slash-commands-2026" aria-label="Permalink to &quot;Claude Code 新工具與 Slash Commands（2026）&quot;">​</a></h1><blockquote><p>來源：23-whats-new-w13-w17.md / 26-new-features-2026-q1.md / 27-whats-new-w18-w19.md / 2026-w20 整合<br> 整理日期：2026-05-28<br> 涵蓋版本：v2.1.83 → v2.1.142（W13–W20）</p></blockquote><p>補充各主題章節未收錄的使用者介面、終端體驗、及新增 slash commands。</p><hr><h2 id="一、computer-use-—-桌面與-cli-控制" tabindex="-1">一、Computer Use — 桌面與 CLI 控制 <a class="header-anchor" href="#一、computer-use-—-桌面與-cli-控制" aria-label="Permalink to &quot;一、Computer Use — 桌面與 CLI 控制&quot;">​</a></h2><h3 id="desktop-app-w13-research-preview" tabindex="-1">Desktop App（W13, research preview） <a class="header-anchor" href="#desktop-app-w13-research-preview" aria-label="Permalink to &quot;Desktop App（W13, research preview）&quot;">​</a></h3><p>在 Desktop app 中直接控制真實桌面（原生 app、iOS simulator、硬體 control panel）。預設關閉，每次操作前詢問確認。</p><p>適用場景：</p><ul><li>沒有 API 的 app</li><li>專有工具或純 GUI 工具</li><li>iOS simulator 互動測試</li></ul><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; Open the iOS simulator, tap through onboarding, and screenshot each step</span></span></code></pre></div><h3 id="cli-擴展-w14-research-preview" tabindex="-1">CLI 擴展（W14, research preview） <a class="header-anchor" href="#cli-擴展-w14-research-preview" aria-label="Permalink to &quot;CLI 擴展（W14, research preview）&quot;">​</a></h3><p>CLI 也可使用 Computer Use：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/mcp → 找到 computer-use → 開啟</span></span></code></pre></div><hr><h2 id="二、terminal-ui-功能" tabindex="-1">二、Terminal UI 功能 <a class="header-anchor" href="#二、terminal-ui-功能" aria-label="Permalink to &quot;二、Terminal UI 功能&quot;">​</a></h2><h3 id="flicker-free-rendering-w14-v2-1-89" tabindex="-1">Flicker-free Rendering（W14, v2.1.89） <a class="header-anchor" href="#flicker-free-rendering-w14-v2-1-89" aria-label="Permalink to &quot;Flicker-free Rendering（W14, v2.1.89）&quot;">​</a></h3><p>Alt-screen renderer，prompt input 釘在底部，支援跨長對話的滑鼠選取，消除重繪 flicker。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> CLAUDE_CODE_NO_FLICKER</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span></span></code></pre></div><p>取消：<code>unset CLAUDE_CODE_NO_FLICKER</code></p><h3 id="tui-—-即時切換-renderer-w16" tabindex="-1"><code>/tui</code> — 即時切換 Renderer（W16） <a class="header-anchor" href="#tui-—-即時切換-renderer-w16" aria-label="Permalink to &quot;\`/tui\` — 即時切換 Renderer（W16）&quot;">​</a></h3><p>在 session 中隨時切換 classic / flicker-free renderer，不需重啟：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; /tui</span></span></code></pre></div><h3 id="custom-themes-—-自訂配色-w17-v2-1-118" tabindex="-1">Custom Themes — 自訂配色（W17, v2.1.118） <a class="header-anchor" href="#custom-themes-—-自訂配色-w17-v2-1-118" aria-label="Permalink to &quot;Custom Themes — 自訂配色（W17, v2.1.118）&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; /theme    # 開啟 theme picker</span></span></code></pre></div><p>手動編輯 <code>~/.claude/themes/</code> 中的 JSON（選擇 base preset 並覆蓋特定 token）。Plugin 也可打包 theme 一起發布。</p><h3 id="vim-visual-mode-w17" tabindex="-1">Vim Visual Mode（W17） <a class="header-anchor" href="#vim-visual-mode-w17" aria-label="Permalink to &quot;Vim Visual Mode（W17）&quot;">​</a></h3><p>在 prompt input 中使用 vim 選取：</p><table tabindex="0"><thead><tr><th>按鍵</th><th>功能</th></tr></thead><tbody><tr><td><code>v</code></td><td>字元選取模式</td></tr><tr><td><code>V</code></td><td>行選取模式</td></tr></tbody></table><p>支援完整 vim operator（d、y、c 等）。</p><hr><h2 id="三、session-管理新指令" tabindex="-1">三、Session 管理新指令 <a class="header-anchor" href="#三、session-管理新指令" aria-label="Permalink to &quot;三、Session 管理新指令&quot;">​</a></h2><h3 id="session-recap-w16-other-wins-→-w17-正式功能" tabindex="-1">Session Recap（W16 Other wins → W17 正式功能） <a class="header-anchor" href="#session-recap-w16-other-wins-→-w17-正式功能" aria-label="Permalink to &quot;Session Recap（W16 Other wins → W17 正式功能）&quot;">​</a></h3><p>切換 focus 後回到 session 時顯示一行摘要，適合同時跑多個 Claude session：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; /recap    # 手動觸發</span></span>
<span class="line"><span># 輸出範例：* recap: Fixing the post-submit transcript shift bug. PR #29869. Next: ...</span></span></code></pre></div><p>在 <code>/config</code> 關閉自動 recap。</p><h3 id="pr-url-恢復-session-w18-v2-1-122" tabindex="-1">PR URL 恢復 Session（W18, v2.1.122） <a class="header-anchor" href="#pr-url-恢復-session-w18-v2-1-122" aria-label="Permalink to &quot;PR URL 恢復 Session（W18, v2.1.122）&quot;">​</a></h3><p>在 <code>/resume</code> picker 中貼入 PR URL（輸入第一個字元進入搜尋模式），列表自動過濾到建立該 PR 的 session：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --from-pr</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1234</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         # CLI 直接指定 PR 號</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --from-pr</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">github_ur</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">l</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 或直接貼 PR URL</span></span></code></pre></div><p>支援 GitHub、GitHub Enterprise、GitLab、Bitbucket 的 PR/MR URL。</p><hr><h2 id="四、-insights-—-工作流自我診斷-2026-02-04" tabindex="-1">四、/insights — 工作流自我診斷（2026-02-04） <a class="header-anchor" href="#四、-insights-—-工作流自我診斷-2026-02-04" aria-label="Permalink to &quot;四、/insights — 工作流自我診斷（2026-02-04）&quot;">​</a></h2><p>來源：Thariq（@trq212，Anthropic Claude Code 核心成員）</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; /insights</span></span></code></pre></div><p>讀取過去一個月的 message history，輸出三份分析：</p><ol><li><strong>專案摘要</strong>：這個月在做什麼（專案類型、主要任務）</li><li><strong>使用模式分析</strong>：哪些功能用得多、哪些沒用到</li><li><strong>工作流改進建議</strong>：基於使用模式提出具體改進</li></ol><p><strong>使用時機：</strong></p><ul><li>Session 初期診斷：了解上個月工作模式，確認方向</li><li>定期複查（每週或每月）：檢視工作流是否退步或可改進</li><li>學習新功能前：先看建議，確認哪些對你特別有價值</li></ul><p><strong>注意：</strong></p><ul><li>一個月 history 的 token 量可能相當大，初次執行前確認 context 用量</li><li>若常用 <code>/clear</code>，history 可能不連貫，建議品質會下降</li></ul><hr><h2 id="五、-powerup-—-互動式功能教學-w14" tabindex="-1">五、/powerup — 互動式功能教學（W14） <a class="header-anchor" href="#五、-powerup-—-互動式功能教學-w14" aria-label="Permalink to &quot;五、/powerup — 互動式功能教學（W14）&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; /powerup</span></span></code></pre></div><p>內建動畫 demo 的互動式課程，直接在 terminal 中教學 Claude Code 功能，適合新成員或想探索未用過功能的用戶。</p><hr><h2 id="六、-terminal-setup-w18" tabindex="-1">六、/terminal-setup（W18） <a class="header-anchor" href="#六、-terminal-setup-w18" aria-label="Permalink to &quot;六、/terminal-setup（W18）&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; /terminal-setup</span></span></code></pre></div><p>啟用 iTerm2 clipboard access，讓 <code>/copy</code> 指令在 tmux 中也能正常運作。</p><hr><h2 id="七、-feedback-—-跨-session-回報-w20" tabindex="-1">七、/feedback — 跨 Session 回報（W20） <a class="header-anchor" href="#七、-feedback-—-跨-session-回報-w20" aria-label="Permalink to &quot;七、/feedback — 跨 Session 回報（W20）&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; /feedback</span></span></code></pre></div><p>W20 更新：可附加最近 24 小時或 7 天的 sessions，用於回報跨多個 session 的問題。</p><hr><h2 id="速查表" tabindex="-1">速查表 <a class="header-anchor" href="#速查表" aria-label="Permalink to &quot;速查表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指令 / 功能</th><th>版本</th><th>主要用途</th></tr></thead><tbody><tr><td>Computer Use（Desktop）</td><td>W13</td><td>控制真實桌面 / iOS sim</td></tr><tr><td>Computer Use（CLI）</td><td>W14</td><td>CLI 版本（research preview）</td></tr><tr><td>Flicker-free Rendering</td><td>W14</td><td>無閃爍 terminal UI</td></tr><tr><td><code>/tui</code></td><td>W16</td><td>即時切換 renderer</td></tr><tr><td>Custom Themes</td><td>W17</td><td>自訂配色方案</td></tr><tr><td>Vim visual mode</td><td>W17</td><td>v/V 選取 operator</td></tr><tr><td>Session Recap / <code>/recap</code></td><td>W17</td><td>多 session 工作流摘要</td></tr><tr><td>PR URL Session Resume</td><td>W18</td><td>從 PR URL 恢復 session</td></tr><tr><td><code>/insights</code></td><td>2026-02</td><td>工作流自我診斷</td></tr><tr><td><code>/powerup</code></td><td>W14</td><td>互動式功能教學</td></tr><tr><td><code>/terminal-setup</code></td><td>W18</td><td>iTerm2 tmux clipboard</td></tr><tr><td><code>/feedback</code> 跨 session</td><td>W20</td><td>附加歷史 sessions 回報</td></tr></tbody></table>`,64)])])}const m=t(d,[["render",r]]);export{u as __pageData,m as default};
